"use client";
import { useParams } from "next/navigation";
import { Product } from "@/types";
import { mockProducts } from "../../../services/mockData";
import Image from "next/image";
import { Plus } from "lucide-react";
import { motion } from "framer-motion";

export default function ProductDetails() {
  const params = useParams();
  const { id } = params as { id: string };
  const product: Product | undefined = mockProducts.find((p) => p.id === id);

  if (!product) {
    return (
      <div className="flex flex-col items-center justify-center h-[60vh] text-2xl font-bold text-gray-500">
        Товар не знайдено
      </div>
    );
  }

  return (
    <motion.div
      initial={{ opacity: 0, y: 40 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.6, ease: "easeOut" }}
      className="min-h-screen flex flex-col items-center bg-white"
    >
      <div className="w-full max-w-4xl mt-8 p-6 rounded-2xl border border-gray-200 shadow-lg bg-white flex flex-col md:flex-row gap-8">
        {/* Left Side: Image */}
        <motion.div
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ duration: 0.7, ease: "easeOut" }}
          className="md:w-3/5 w-full flex items-center justify-center relative"
        >
          <div className="absolute inset-0 rounded-2xl bg-gradient-to-br from-yellow-100 via-white to-orange-100 blur-xl opacity-60 -z-10" />
          <Image
            src={product.image.startsWith("/images/") ? product.image : `/images/${product.image}`}
            alt={product.title}
            width={340}
            height={260}
            className="rounded-xl object-contain shadow-xl"
            priority
          />
        </motion.div>

        {/* Right Side: Info */}
        <motion.div
          initial={{ opacity: 0, x: 40 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ duration: 0.7, ease: "easeOut", delay: 0.2 }}
          className="md:w-2/5 w-full flex flex-col justify-center gap-6"
        >
          <h1 className="text-3xl md:text-4xl font-bold mb-2 text-gray-800 tracking-tight">
            {product.title}
          </h1>
          <p className="text-lg text-gray-600 mb-2">
            {product.description}
          </p>
          <div className="text-base font-medium text-gray-700 mb-1">
            <span className="font-semibold">запас:</span> {product.stock}
          </div>
          <div className="flex items-center gap-4 mt-6">
            <button
              className="w-12 h-12 rounded-full bg-orange-400 hover:bg-orange-500 flex items-center justify-center shadow-lg transition-colors duration-200"
              aria-label="Додати в кошик"
            >
              <Plus size={28} color="#fff" />
            </button>
            <span className="text-2xl font-bold text-gray-900 underline decoration-dotted decoration-2 underline-offset-4">
              {product.price}$
            </span>
          </div>
        </motion.div>
      </div>
    </motion.div>
  );
}
